CREATE TRIGGER [dbo].[DefectCategory_History]ON [dbo].[DefectCategory]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.DefectCategoryId IS NOT NULL AND d.DefectCategoryId IS NULL THEN 'I' 		WHEN i.DefectCategoryId IS NOT NULL AND d.DefectCategoryId IS NOT NULL THEN 'U' 		WHEN i.DefectCategoryId IS NULL AND d.DefectCategoryId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.DefectCategoryId = d.DefectCategoryId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_DefectCategory([DefectCategoryId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [DefectCategoryId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_DefectCategory([DefectCategoryId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [DefectCategoryId], [Name], [Description], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND